class Record { public string Date; public string Product; public int Qty; public Record(string d, string p, int q) { Date=d; Product=p; Qty=q; } }
var records = new List<Record>();
records.Add(new Record("5/1", "A", 1000));
records.Add(new Record("5/1", "B", 800));
records.Add(new Record("5/2", "A", 1200));
records.Add(new Record("5/2", "B", 900));
records.Add(new Record("5/3", "A", 1100));
records.Add(new Record("5/3", "B", 1300));

Print("--- 5/2 ---");
foreach (var r in records)
    if (r.Date == "5/2") Print($"{r.Date} {r.Product}: {r.Qty}");
Print("--- A ---");
foreach (var r in records)
    if (r.Product == "A") Print($"{r.Date} {r.Product}: {r.Qty}");
Print("--- Qty>1100 ---");
foreach (var r in records)
    if (r.Qty > 1100) Print($"{r.Date} {r.Product}: {r.Qty}");
Print("查询完成");
